    16→func TestAuthMiddlewareValidKey(t *testing.T) {
    17→	store := &mockKeyStore{valid: true}
    18→	handler := Auth(store)(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
    19→		w.WriteHeader(http.StatusOK)
    20→	}))
    21→
    22→	w := httptest.NewRecorder()
    23→	r := httptest.NewRequest(http.MethodGet, "/", nil)
    24→	r.Header.Set("Authorization", "Bearer valid-key-123")
    25→	handler.ServeHTTP(w, r)
    26→
    27→	if w.Code != http.StatusOK {
    28→		t.Fatalf("expected status 200, got %d", w.Code)
    29→	}
    30→}
    31→
    32→func TestAuthMiddlewareMissingKey(t *testing.T) {
    33→	store := &mockKeyStore{valid: true}
    34→	handler := Auth(store)(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
    35→		w.WriteHeader(http.StatusOK)
    36→	}))
    37→
    38→	w := httptest.NewRecorder()
    39→	r := httptest.NewRequest(http.MethodGet, "/", nil)
    40→	// No Authorization header
    41→	handler.ServeHTTP(w, r)
    42→
    43→	if w.Code != http.StatusUnauthorized {
    44→		t.Fatalf("expected status 401, got %d", w.Code)
    45→	}
    46→
    47→	var got struct {
    48→		Error struct {
    49→			Code    string `json:"code"`
    50→			Message string `json:"message"`
    51→		} `json:"error"`
    52→	}
    53→	if err := json.NewDecoder(w.Body).Decode(&got); err != nil {
    54→		t.Fatalf("decode: %v", err)
    55→	}
    56→	if got.Error.Code != "unauthorized" {
    57→		t.Fatalf("expected error.code=unauthorized, got %s", got.Error.Code)
    58→	}
    59→	if got.Error.Message != "Missing API key" {
    60→		t.Fatalf("expected message=Missing API key, got %s", got.Error.Message)
    61→	}
    62→}
