    96→func TestRateLimitMiddleware(t *testing.T) {
    97→	handler := RateLimit(1, 2)(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
    98→		w.WriteHeader(http.StatusOK)
    99→	}))
   100→
   101→	// First two requests should succeed (burst=2)
   102→	for i := range 2 {
   103→		w := httptest.NewRecorder()
   104→		r := httptest.NewRequest(http.MethodGet, "/", nil)
   105→		r.RemoteAddr = "192.168.1.1:12345"
   106→		handler.ServeHTTP(w, r)
   107→		if w.Code != http.StatusOK {
   108→			t.Fatalf("request %d: expected status 200, got %d", i+1, w.Code)
   109→		}
   110→	}
   111→
   112→	// Third request should be rate limited
   113→	w := httptest.NewRecorder()
   114→	r := httptest.NewRequest(http.MethodGet, "/", nil)
   115→	r.RemoteAddr = "192.168.1.1:12345"
   116→	handler.ServeHTTP(w, r)
   117→
   118→	if w.Code != http.StatusTooManyRequests {
   119→		t.Fatalf("third request: expected status 429, got %d", w.Code)
   120→	}
   121→	if v := w.Header().Get("Retry-After"); v != "1" {
   122→		t.Fatalf("expected Retry-After=1, got %s", v)
   123→	}
   124→
   125→	var got struct {
   126→		Error struct {
   127→			Code string `json:"code"`
   128→		} `json:"error"`
   129→	}
   130→	if err := json.NewDecoder(w.Body).Decode(&got); err != nil {
   131→		t.Fatalf("decode: %v", err)
   132→	}
   133→	if got.Error.Code != "rate_limited" {
   134→		t.Fatalf("expected error.code=rate_limited, got %s", got.Error.Code)
   135→	}
   136→}
   137→
   138→func TestRateLimitKeysByBearer(t *testing.T) {
   139→	handler := RateLimit(1, 1)(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
   140→		w.WriteHeader(http.StatusOK)
   141→	}))
   142→
   143→	// First request with key A should succeed
   144→	w1 := httptest.NewRecorder()
   145→	r1 := httptest.NewRequest(http.MethodGet, "/", nil)
   146→	r1.Header.Set("Authorization", "Bearer key-a")
   147→	handler.ServeHTTP(w1, r1)
   148→	if w1.Code != http.StatusOK {
   149→		t.Fatalf("key-a first request: expected 200, got %d", w1.Code)
   150→	}
   151→
   152→	// First request with key B should also succeed (separate limiter)
   153→	w2 := httptest.NewRecorder()
   154→	r2 := httptest.NewRequest(http.MethodGet, "/", nil)
   155→	r2.Header.Set("Authorization", "Bearer key-b")
   156→	handler.ServeHTTP(w2, r2)
   157→	if w2.Code != http.StatusOK {
   158→		t.Fatalf("key-b first request: expected 200, got %d", w2.Code)
   159→	}
   160→
   161→	// Second request with key A should be rate limited
   162→	w3 := httptest.NewRecorder()
   163→	r3 := httptest.NewRequest(http.MethodGet, "/", nil)
   164→	r3.Header.Set("Authorization", "Bearer key-a")
   165→	handler.ServeHTTP(w3, r3)
   166→	if w3.Code != http.StatusTooManyRequests {
   167→		t.Fatalf("key-a second request: expected 429, got %d", w3.Code)
   168→	}
   169→}
