     4→import { useEffect, useState } from "react";
     5→import useSWR, { mutate } from "swr";
     6→import { useRouter } from "next/navigation";
     7→import { StatsCards } from "@/components/dashboard/stats-cards";
     8→import { ReleaseTrendChart } from "@/components/dashboard/release-trend-chart";
     9→import { UnifiedFeed } from "@/components/dashboard/unified-feed";
    10→import { DashboardEmptyState } from "@/components/dashboard/empty-state";
    11→import { DiscoverySection } from "@/components/dashboard/discovery-section";
    12→import { projects as projectsApi } from "@/lib/api/client";
    13→import { Search } from "lucide-react";
    14→
    15→const SSE_BASE = process.env.NEXT_PUBLIC_API_URL || "/api/v1";
    16→
    17→export default function DashboardPage() {
    18→  const router = useRouter();
    19→  const [repoUrl, setRepoUrl] = useState("");
    20→  const { data: projectsData, isLoading } = useSWR("projects-for-dashboard", () =>
    21→    projectsApi.list()
    22→  );
    23→
    24→  // Listen to SSE events and revalidate dashboard data on new releases
    25→  useEffect(() => {
    26→    let es: EventSource | null = null;
    27→    let retryTimer: ReturnType<typeof setTimeout> | null = null;
    28→
    29→    function connect() {
    30→      try {
    31→        es = new EventSource(`${SSE_BASE}/events`);
    32→        es.onmessage = () => {
    33→          // Revalidate all dashboard SWR keys on any event
    34→          mutate((key) => typeof key === "string" && (
    35→            key === "stats" ||
    36→            key.startsWith("trend-") ||
    37→            key === "unified-feed"
    38→          ), undefined, { revalidate: true });
    39→        };
    40→        es.onerror = () => {
    41→          es?.close();
    42→          retryTimer = setTimeout(connect, 5000);
    43→        };
    44→      } catch {
    45→        retryTimer = setTimeout(connect, 5000);
    46→      }
    47→    }
    48→
    49→    connect();
    50→    return () => {
    51→      es?.close();
    52→      if (retryTimer) clearTimeout(retryTimer);
    53→    };
    54→  }, []);
    55→
    56→  const hasProjects = !isLoading && projectsData?.data && projectsData.data.length > 0;
    57→
    58→  return (
    59→    <div className="space-y-6">
    60→      <h1
    61→        style={{
    62→          fontFamily: "var(--font-fraunces)",
    63→          fontSize: "24px",
    64→          fontWeight: 700,
    65→          color: "#111113",
    66→        }}
    67→      >
    68→        Dashboard
    69→      </h1>
    70→
    71→      <DiscoverySection />
    72→
    73→      {/* Quick Onboard inline */}
    74→      <div
    75→        className="rounded-lg bg-white px-5 py-3"
    76→        style={{ border: "1px solid #e8e8e5" }}
    77→      >
    78→        <div className="flex items-center gap-4">
    79→          <span
    80→            className="flex-shrink-0"
    81→            style={{
    82→              fontFamily: "var(--font-fraunces)",
    83→              fontSize: "14px",
    84→              fontWeight: 600,
    85→              color: "#111113",
    86→            }}
    87→          >
    88→            Quick Onboard
    89→          </span>
    90→          <div className="flex flex-1 items-center gap-2">
    91→            <input
    92→              type="text"
    93→              value={repoUrl}
    94→              onChange={(e) => setRepoUrl(e.target.value)}
    95→              placeholder="owner/repo or https://github.com/owner/repo"
    96→              className="flex-1 rounded-md border px-3 py-1.5 text-[13px] focus:outline-none"
    97→              style={{
    98→                borderColor: "#e8e8e5",
    99→                color: "#111113",
   100→                fontFamily: "'JetBrains Mono', monospace",
   101→                maxWidth: 400,
   102→              }}
   103→              onFocus={(e) => { e.currentTarget.style.borderColor = "#e8601a"; }}
   104→              onBlur={(e) => { e.currentTarget.style.borderColor = "#e8e8e5"; }}
   105→              onKeyDown={(e) => {
   106→                if (e.key === "Enter" && repoUrl.trim()) {
   107→                  router.push(`/onboard?repo=${encodeURIComponent(repoUrl.trim())}`);
   108→                }
   109→              }}
   110→            />
   111→            <button
   112→              onClick={() => {
   113→                if (repoUrl.trim()) {
   114→                  router.push(`/onboard?repo=${encodeURIComponent(repoUrl.trim())}`);
   115→                }
   116→              }}
   117→              disabled={!repoUrl.trim()}
   118→              className="flex items-center gap-1.5 rounded-md px-3 py-1.5 text-[13px] font-medium text-white transition-opacity hover:opacity-90 disabled:opacity-40 disabled:cursor-not-allowed"
   119→              style={{ backgroundColor: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
   120→            >
   121→              <Search className="h-3.5 w-3.5" />
   122→              Scan
   123→            </button>
   124→          </div>
   125→          <span className="text-[12px] flex-shrink-0" style={{ color: "#9ca3af" }}>
   126→            Scan a repo for dependencies
   127→          </span>
   128→        </div>
   129→      </div>
   130→
   131→      {hasProjects ? (
   132→        <>
   133→          <StatsCards />
   134→          <div className="grid gap-4 lg:grid-cols-2">
   135→            <ReleaseTrendChart />
   136→            <UnifiedFeed />
   137→          </div>
   138→        </>
   139→      ) : isLoading ? (
   140→        <div
   141→          className="py-16 text-center"
   142→          style={{
   143→            fontFamily: "var(--font-dm-sans)",
   144→            fontSize: "13px",
   145→            color: "#6b7280",
   146→          }}
   147→        >
   148→          Loading...
   149→        </div>
   150→      ) : (
   151→        <DashboardEmptyState />
   152→      )}
   153→    </div>
   154→  );
   155→}
