     1→package api
     2→
     3→import (
     4→	"net/http"
     5→	"os"
     6→	"path/filepath"
     7→	"strings"
     8→)
     9→
    10→// dynamicRoutes maps URL path patterns to their static export HTML files.
    11→// Next.js static export generates these with placeholder param "0".
    12→// The order matters: more specific patterns must come first.
    13→var dynamicRoutes = []struct {
    14→	// segments is the split URL pattern where "*" matches any single segment.
    15→	segments []string
    16→	// file is the path to the pre-rendered HTML relative to webDir.
    17→	file string
    18→}{
    19→	{[]string{"projects", "*", "semantic-releases", "*"}, "projects/0/semantic-releases/0.html"},
    20→	{[]string{"projects", "*", "agent"}, "projects/0/agent.html"},
    21→	{[]string{"projects", "*"}, "projects/0.html"},
    22→	{[]string{"releases", "*"}, "releases/0.html"},
    23→}
    24→
    25→// matchDynamicRoute checks if the URL path matches a dynamic route pattern
    26→// and returns the corresponding HTML file path, or empty string if no match.
    27→func matchDynamicRoute(urlPath string) string {
    28→	parts := strings.Split(strings.Trim(urlPath, "/"), "/")
    29→	for _, route := range dynamicRoutes {
    30→		if len(parts) != len(route.segments) {
    31→			continue
    32→		}
    33→		match := true
    34→		for i, seg := range route.segments {
    35→			if seg != "*" && seg != parts[i] {
    36→				match = false
    37→				break
    38→			}
    39→		}
    40→		if match {
    41→			return route.file
    42→		}
    43→	}
    44→	return ""
    45→}
    46→
    47→// RegisterFrontend serves the Next.js static export from webDir.
    48→// It handles dynamic routes by mapping them to their pre-rendered HTML shells,
    49→// which then fetch real data client-side via SWR.
    50→func RegisterFrontend(mux *http.ServeMux, webDir string) {
    51→	mux.Handle("GET /", http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
    52→		// Try the exact path first (static assets like JS, CSS, images)
    53→		path := filepath.Join(webDir, filepath.Clean(r.URL.Path))
    54→		if info, err := os.Stat(path); err == nil && !info.IsDir() {
    55→			http.ServeFile(w, r, path)
    56→			return
    57→		}
    58→		// Try path + ".html" (Next.js static export convention for static pages)
    59→		if info, err := os.Stat(path + ".html"); err == nil && !info.IsDir() {
    60→			http.ServeFile(w, r, path+".html")
    61→			return
    62→		}
    63→		// Try dynamic route patterns (e.g. /projects/{id} → projects/0.html)
    64→		if file := matchDynamicRoute(r.URL.Path); file != "" {
    65→			http.ServeFile(w, r, filepath.Join(webDir, file))
    66→			return
    67→		}
    68→		// Fall back to index.html for unmatched routes
    69→		http.ServeFile(w, r, filepath.Join(webDir, "index.html"))
    70→	}))
    71→}
