package db

import (
	"context"
	"fmt"

	"github.com/jackc/pgx/v5/pgxpool"
	"github.com/riverqueue/river/riverdriver/riverpgxv5"
	"github.com/riverqueue/river/rivermigrate"
)

const schema = `
-- Tracked software projects (the central entity)
CREATE TABLE IF NOT EXISTS projects (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    name VARCHAR(100) NOT NULL UNIQUE,
    description TEXT,
    agent_prompt TEXT,
    agent_rules JSONB,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- Configured ingestion sources (polling-based: GitHub, Docker Hub)
CREATE TABLE IF NOT EXISTS sources (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    project_id UUID NOT NULL REFERENCES projects(id) ON DELETE CASCADE,
    provider VARCHAR(50) NOT NULL,
    repository VARCHAR(255) NOT NULL,
    poll_interval_seconds INT DEFAULT 86400,
    enabled BOOLEAN DEFAULT true,
    config JSONB,
    last_polled_at TIMESTAMPTZ,
    last_error TEXT,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW(),
    UNIQUE(provider, repository)
);

-- Context sources (read-only references for agent research)
CREATE TABLE IF NOT EXISTS context_sources (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    project_id UUID NOT NULL REFERENCES projects(id) ON DELETE CASCADE,
    type VARCHAR(50) NOT NULL,
    name VARCHAR(100) NOT NULL,
    config JSONB NOT NULL,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- Source-level releases (detected from polling sources)
CREATE TABLE IF NOT EXISTS releases (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    source_id UUID NOT NULL REFERENCES sources(id) ON DELETE CASCADE,
    version VARCHAR(100) NOT NULL,
    raw_data JSONB,
    released_at TIMESTAMPTZ,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    UNIQUE(source_id, version)
);

-- Project-level semantic releases (AI-generated, correlating source releases)
CREATE TABLE IF NOT EXISTS semantic_releases (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    project_id UUID NOT NULL REFERENCES projects(id) ON DELETE CASCADE,
    version VARCHAR(100) NOT NULL,
    report JSONB,
    status VARCHAR(50) NOT NULL DEFAULT 'pending',
    error TEXT,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    completed_at TIMESTAMPTZ,
    UNIQUE(project_id, version)
);

-- Join table: which source releases compose a semantic release
CREATE TABLE IF NOT EXISTS semantic_release_sources (
    semantic_release_id UUID NOT NULL REFERENCES semantic_releases(id) ON DELETE CASCADE,
    release_id UUID NOT NULL REFERENCES releases(id) ON DELETE CASCADE,
    PRIMARY KEY (semantic_release_id, release_id)
);

-- Notification channels (standalone)
CREATE TABLE IF NOT EXISTS notification_channels (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    name VARCHAR(100) NOT NULL,
    type VARCHAR(50) NOT NULL,
    config JSONB NOT NULL,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- Subscriptions: two types (source releases and semantic releases)
CREATE TABLE IF NOT EXISTS subscriptions (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    channel_id UUID NOT NULL REFERENCES notification_channels(id) ON DELETE CASCADE,
    type VARCHAR(50) NOT NULL CHECK (type IN ('source_release', 'semantic_release')),
    source_id UUID REFERENCES sources(id) ON DELETE CASCADE,
    project_id UUID REFERENCES projects(id) ON DELETE CASCADE,
    version_filter TEXT,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    CHECK (
        (type = 'source_release'   AND source_id  IS NOT NULL AND project_id IS NULL) OR
        (type = 'semantic_release' AND project_id IS NOT NULL AND source_id  IS NULL)
    )
);

-- Agent runs (scoped to project)
CREATE TABLE IF NOT EXISTS agent_runs (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    project_id UUID NOT NULL REFERENCES projects(id) ON DELETE CASCADE,
    semantic_release_id UUID REFERENCES semantic_releases(id) ON DELETE SET NULL,
    trigger VARCHAR(100) NOT NULL,
    status VARCHAR(50) NOT NULL DEFAULT 'pending',
    prompt_used TEXT,
    error TEXT,
    started_at TIMESTAMPTZ,
    completed_at TIMESTAMPTZ,
    created_at TIMESTAMPTZ DEFAULT NOW()
);

ALTER TABLE agent_runs ADD COLUMN IF NOT EXISTS version VARCHAR(100);

-- API authentication keys
CREATE TABLE IF NOT EXISTS api_keys (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    name VARCHAR(100) NOT NULL,
    key_hash VARCHAR(64) NOT NULL UNIQUE,
    key_prefix VARCHAR(12) NOT NULL,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    last_used_at TIMESTAMPTZ
);

-- Trigger for SSE: notify on new releases
CREATE OR REPLACE FUNCTION notify_release_created() RETURNS trigger AS $$
BEGIN
    PERFORM pg_notify('release_events', json_build_object('type', 'release', 'id', NEW.id)::text);
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS release_created_trigger ON releases;
CREATE TRIGGER release_created_trigger
    AFTER INSERT ON releases
    FOR EACH ROW EXECUTE FUNCTION notify_release_created();

-- Trigger for SSE: notify on semantic release completion
CREATE OR REPLACE FUNCTION notify_semantic_release() RETURNS trigger AS $$
BEGIN
    IF NEW.status = 'completed' AND (OLD IS NULL OR OLD.status != 'completed') THEN
        PERFORM pg_notify('release_events', json_build_object('type', 'semantic_release', 'id', NEW.id)::text);
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS semantic_release_trigger ON semantic_releases;
CREATE TRIGGER semantic_release_trigger
    AFTER INSERT OR UPDATE ON semantic_releases
    FOR EACH ROW EXECUTE FUNCTION notify_semantic_release();

-- Release TODOs (acknowledge/resolve tracking)
CREATE TABLE IF NOT EXISTS release_todos (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    release_id UUID REFERENCES releases(id) ON DELETE CASCADE,
    semantic_release_id UUID REFERENCES semantic_releases(id) ON DELETE CASCADE,
    status VARCHAR(20) NOT NULL DEFAULT 'pending',
    created_at TIMESTAMPTZ DEFAULT NOW(),
    acknowledged_at TIMESTAMPTZ,
    resolved_at TIMESTAMPTZ,
    CHECK (
        (release_id IS NOT NULL AND semantic_release_id IS NULL) OR
        (release_id IS NULL AND semantic_release_id IS NOT NULL)
    )
);
CREATE UNIQUE INDEX IF NOT EXISTS idx_release_todos_release_id ON release_todos(release_id) WHERE release_id IS NOT NULL;
CREATE UNIQUE INDEX IF NOT EXISTS idx_release_todos_semantic_release_id ON release_todos(semantic_release_id) WHERE semantic_release_id IS NOT NULL;

-- Onboarding scans (GitHub repo dependency detection)
CREATE TABLE IF NOT EXISTS onboard_scans (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    repo_url TEXT NOT NULL,
    status VARCHAR(50) NOT NULL DEFAULT 'pending',
    results JSONB,
    error TEXT,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    started_at TIMESTAMPTZ,
    completed_at TIMESTAMPTZ
);
`

// RunMigrations applies River's schema and the application schema. Idempotent — safe to call on every startup.
func RunMigrations(ctx context.Context, pool *pgxpool.Pool) error {
	migrator, err := rivermigrate.New(riverpgxv5.New(pool), nil)
	if err != nil {
		return fmt.Errorf("create river migrator: %w", err)
	}
	if _, err := migrator.Migrate(ctx, rivermigrate.DirectionUp, nil); err != nil {
		return fmt.Errorf("river migrations: %w", err)
	}

	if _, err := pool.Exec(ctx, schema); err != nil {
		return fmt.Errorf("app migrations: %w", err)
	}

	// Migrate existing subscription type values: source→source_release, project→semantic_release.
	// Drop old CHECK constraints first (both the named type check and the unnamed
	// composite check referencing old values), then UPDATE data, then re-add constraints.
	if _, err := pool.Exec(ctx, `
		ALTER TABLE subscriptions DROP CONSTRAINT IF EXISTS subscriptions_type_check;
		ALTER TABLE subscriptions DROP CONSTRAINT IF EXISTS subscriptions_check;
		UPDATE subscriptions SET type = 'source_release' WHERE type = 'source';
		UPDATE subscriptions SET type = 'semantic_release' WHERE type = 'project';
		ALTER TABLE subscriptions ADD CONSTRAINT subscriptions_type_check CHECK (type IN ('source_release', 'semantic_release'));
		ALTER TABLE subscriptions ADD CONSTRAINT subscriptions_check CHECK (
			(type = 'source_release'   AND source_id IS NOT NULL AND project_id IS NULL) OR
			(type = 'semantic_release' AND project_id IS NOT NULL AND source_id IS NULL)
		);
	`); err != nil {
		return fmt.Errorf("subscription type migration: %w", err)
	}

	if _, err := pool.Exec(ctx, `
		ALTER TABLE sources ADD COLUMN IF NOT EXISTS version_filter_include TEXT;
		ALTER TABLE sources ADD COLUMN IF NOT EXISTS version_filter_exclude TEXT;
	`); err != nil {
		return fmt.Errorf("source version filter migration: %w", err)
	}

	if _, err := pool.Exec(ctx, `
		ALTER TABLE sources ADD COLUMN IF NOT EXISTS exclude_prereleases BOOLEAN DEFAULT false;
	`); err != nil {
		return fmt.Errorf("source exclude_prereleases migration: %w", err)
	}
	return nil
}

package main

import (
	"context"
	"log/slog"
	"net/http"
	"os"
	"os/signal"
	"time"

	"github.com/riverqueue/river"
	agentpkg "github.com/sentioxyz/changelogue/internal/agent"
	"github.com/sentioxyz/changelogue/internal/api"
	"github.com/sentioxyz/changelogue/internal/db"
	"github.com/sentioxyz/changelogue/internal/ingestion"
	"github.com/sentioxyz/changelogue/internal/onboard"
	"github.com/sentioxyz/changelogue/internal/queue"
	"github.com/sentioxyz/changelogue/internal/routing"
)

func main() {
	// Configure log level from LOG_LEVEL env (debug, info, warn, error).
	logLevel := new(slog.LevelVar) // defaults to Info
	switch os.Getenv("LOG_LEVEL") {
	case "debug":
		logLevel.Set(slog.LevelDebug)
	case "warn":
		logLevel.Set(slog.LevelWarn)
	case "error":
		logLevel.Set(slog.LevelError)
	}
	slog.SetDefault(slog.New(slog.NewTextHandler(os.Stderr, &slog.HandlerOptions{Level: logLevel})))

	ctx, stop := signal.NotifyContext(context.Background(), os.Interrupt)
	defer stop()

	dbURL := envOr("DATABASE_URL", "postgres://localhost:5432/changelogue?sslmode=disable")
	addr := envOr("LISTEN_ADDR", ":8080")
	noAuth := os.Getenv("NO_AUTH") == "true"

	// Database
	pool, err := db.NewPool(ctx, dbURL)
	if err != nil {
		slog.Error("database connection failed", "err", err)
		os.Exit(1)
	}
	defer pool.Close()

	if err := db.RunMigrations(ctx, pool); err != nil {
		slog.Error("migrations failed", "err", err)
		os.Exit(1)
	}

	// API & routing store (created before River so we can register workers)
	// The river client is set to nil initially; TriggerAgentRun (which needs it)
	// won't be called until the server is up and the client is set below.
	pgStore := api.NewPgStore(pool, nil)

	// Register River workers
	workers := river.NewWorkers()
	notifyWorker := routing.NewNotifyWorker(pgStore, os.Getenv("PUBLIC_URL"))
	river.AddWorker(workers, notifyWorker)

	// Agent worker: requires an LLM API key. If unavailable, agent jobs
	// will remain in the queue until the key is configured and the server
	// is restarted.
	llmProvider := envOr("LLM_PROVIDER", "gemini")
	llmModelDefault := "gemini-2.5-flash"
	if llmProvider == "openai" {
		llmModelDefault = "gpt-5.2"
	}
	llmConfig := agentpkg.LLMConfig{
		Provider:      llmProvider,
		Model:         envOr("LLM_MODEL", llmModelDefault),
		GoogleAPIKey:  os.Getenv("GOOGLE_API_KEY"),
		OpenAIAPIKey:  os.Getenv("OPENAI_API_KEY"),
		OpenAIBaseURL: os.Getenv("OPENAI_BASE_URL"),
	}
	agentOrchestrator, err := agentpkg.NewOrchestrator(pgStore, llmConfig, os.Getenv("PUBLIC_URL"))
	if err != nil {
		slog.Warn("agent orchestrator not available — agent jobs will not be processed", "err", err)
	} else {
		agentWorker := agentpkg.NewAgentWorker(agentOrchestrator, pgStore)
		river.AddWorker(workers, agentWorker)
		slog.Info("agent worker registered")
	}

	// Scan worker: requires LLM for dependency extraction
	scanScanner := onboard.NewScanner(http.DefaultClient, "", "")
	var scanExtractor *onboard.DependencyExtractor
	extractorCfg := onboard.ExtractorConfig{
		Provider:      llmConfig.Provider,
		Model:         llmConfig.Model,
		GoogleAPIKey:  llmConfig.GoogleAPIKey,
		OpenAIAPIKey:  llmConfig.OpenAIAPIKey,
		OpenAIBaseURL: llmConfig.OpenAIBaseURL,
	}
	ext, err := onboard.NewDependencyExtractor(ctx, extractorCfg)
	if err != nil {
		slog.Warn("dependency extractor not available", "err", err)
	} else {
		scanExtractor = ext
	}
	scanWorker := onboard.NewScanWorker(pgStore, scanScanner, scanExtractor, pool)
	river.AddWorker(workers, scanWorker)
	slog.Info("scan worker registered")

	riverClient, err := queue.NewRiverClient(pool, workers)
	if err != nil {
		slog.Error("river client failed", "err", err)
		os.Exit(1)
	}

	// Now that the river client exists, set it on the existing pgStore so that
	// all holders (including NotifyWorker) can enqueue agent jobs.
	pgStore.SetRiverClient(riverClient)

	if err := riverClient.Start(ctx); err != nil {
		slog.Error("river start failed", "err", err)
		os.Exit(1)
	}

	// Ingestion layer
	ingestionStore := ingestion.NewPgStore(pool, riverClient)
	svc := ingestion.NewService(ingestionStore)

	loader := ingestion.NewSourceLoader(pool, http.DefaultClient)
	orch := ingestion.NewOrchestrator(svc, loader, pool, 5*time.Minute)

	broadcaster := api.NewBroadcaster()

	mux := http.NewServeMux()

	// Serve frontend static export if available
	if info, err := os.Stat("web/out"); err == nil && info.IsDir() {
		api.RegisterFrontend(mux, "web/out")
		slog.Info("serving frontend from web/out")
	}

	// Register all API v1 routes
	api.RegisterRoutes(mux, api.Dependencies{
		DB:                    pool,
		ProjectsStore:         pgStore,
		ReleasesStore:         pgStore,
		SubscriptionsStore:    pgStore,
		SourcesStore:          pgStore,
		ChannelsStore:         pgStore,
		ContextSourcesStore:   pgStore,
		SemanticReleasesStore: pgStore,
		AgentStore:            pgStore,
		TodosStore:            pgStore,
		OnboardStore:          pgStore,
		PublicURL:             os.Getenv("PUBLIC_URL"),
		KeyStore:              pgStore,
		HealthChecker:         pgStore,
		Broadcaster:           broadcaster,
		NoAuth:                noAuth,
		IngestionService:      svc,
		HTTPClient:            http.DefaultClient,
	})

	srv := &http.Server{Addr: addr, Handler: api.CORS(mux)}

	// Start polling in background
	go orch.Run(ctx)

	// Start PostgreSQL LISTEN/NOTIFY → SSE bridge
	go api.ListenForNotifications(ctx, pool, broadcaster)

	// Start HTTP server
	go func() {
		slog.Info("server starting", "addr", srv.Addr)
		if err := srv.ListenAndServe(); err != http.ErrServerClosed {
			slog.Error("server error", "err", err)
		}
	}()

	<-ctx.Done()
	slog.Info("shutting down")

	shutdownCtx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
	defer cancel()
	riverClient.Stop(shutdownCtx)
	srv.Shutdown(shutdownCtx)
}

func envOr(key, fallback string) string {
	if v := os.Getenv(key); v != "" {
		return v
	}
	return fallback
}

