    40→	getLimiter := func(key string) *rate.Limiter {
    41→		mu.Lock()
    42→		defer mu.Unlock()
    43→		if lim, ok := limiters[key]; ok {
    44→			return lim
    45→		}
    46→		lim := rate.NewLimiter(rate.Limit(rps), burst)
    47→		limiters[key] = lim
