   554→   554→type stateEntry struct {
   555→   555→	expiresAt time.Time
   556→   556→}
   557→   557→
   558→   558→// StateStore holds OAuth state parameters in memory with TTL and size limit.
   559→   559→type StateStore struct {
   560→   560→	mu      sync.Mutex
   561→   561→	entries map[string]stateEntry
   562→   562→	maxSize int
   563→   563→	ttl     time.Duration
   564→   564→}
