   566→   566→// NewStateStore creates a state store with the given max size and TTL per entry.
   567→   567→func NewStateStore(maxSize int, ttl time.Duration) *StateStore {
   568→   568→	return &StateStore{
   569→   569→		entries: make(map[string]stateEntry),
   570→   570→		maxSize: maxSize,
   571→   571→		ttl:     ttl,
   572→   572→	}
   573→   573→}
   574→   574→
   575→   575→// Create generates a random state string and stores it. Returns "" if the store is full.
   576→   576→func (s *StateStore) Create() string {
   577→   577→	s.mu.Lock()
   578→   578→	defer s.mu.Unlock()
   579→   579→
   580→   580→	// Sweep expired before checking size
   581→   581→	now := time.Now()
   582→   582→	for k, v := range s.entries {
   583→   583→		if now.After(v.expiresAt) {
   584→   584→			delete(s.entries, k)
   585→   585→		}
   586→   586→	}
   587→   587→
   588→   588→	if len(s.entries) >= s.maxSize {
   589→   589→		return ""
   590→   590→	}
   591→   591→
   592→   592→	b := make([]byte, 16)
   593→   593→	if _, err := rand.Read(b); err != nil {
   594→   594→		return ""
   595→   595→	}
   596→   596→	state := hex.EncodeToString(b)
   597→   597→	s.entries[state] = stateEntry{expiresAt: now.Add(s.ttl)}
   598→   598→	return state
   599→   599→}

