    10→
    11→type Middleware func(http.Handler) http.Handler
    12→
    13→func Chain(mws ...Middleware) Middleware {
    14→	return func(final http.Handler) http.Handler {
    15→		for i := len(mws) - 1; i >= 0; i-- {
    16→			final = mws[i](final)
    17→		}
    18→		return final
    19→	}
    20→}
    21→
    22→func RequestID(next http.Handler) http.Handler {
    23→	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
    24→		id := uuid.New().String()
    25→		w.Header().Set("X-Request-ID", id)
    26→		next.ServeHTTP(w, r.WithContext(withRequestID(r.Context(), id)))
    27→	})
    28→}
    29→
    30→func Logger(next http.Handler) http.Handler {
    31→	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
    32→		start := time.Now()
    33→		sw := &statusWriter{ResponseWriter: w, status: http.StatusOK}
    34→		next.ServeHTTP(sw, r)
    35→		slog.Info("request",
    36→			"request_id", getRequestID(r.Context()),
    37→			"method", r.Method,
    38→			"path", r.URL.Path,
    39→			"status", sw.status,
    40→			"duration_ms", time.Since(start).Milliseconds(),
    41→		)
    42→	})
    43→}
    44→
    45→type statusWriter struct {
    46→	http.ResponseWriter
    47→	status int
    48→}
    49→
    50→func (w *statusWriter) WriteHeader(code int) {
    51→	w.status = code
    52→	w.ResponseWriter.WriteHeader(code)
    53→}
    54→
    55→func Recovery(next http.Handler) http.Handler {
    56→	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
    57→		defer func() {
    58→			if err := recover(); err != nil {
    59→				slog.Error("panic recovered", "request_id", getRequestID(r.Context()), "error", err)
    60→				RespondError(w, r, http.StatusInternalServerError, "internal_error", "Internal server error")
    61→			}
    62→		}()
    63→		next.ServeHTTP(w, r)
    64→	})
    65→}
    66→
    67→func CORS(next http.Handler) http.Handler {
    68→	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
    69→		w.Header().Set("Access-Control-Allow-Origin", "*")
    70→		w.Header().Set("Access-Control-Allow-Methods", "GET, POST, PUT, PATCH, DELETE, OPTIONS")
    71→		w.Header().Set("Access-Control-Allow-Headers", "Content-Type, Authorization")
    72→		w.Header().Set("Access-Control-Max-Age", "86400")
    73→		if r.Method == http.MethodOptions {
    74→			w.WriteHeader(http.StatusNoContent)
    75→			return
    76→		}
    77→		next.ServeHTTP(w, r)
    78→	})
    79→}
